import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './components/Login';
import CrearOferta from './components/CrearOferta';
import SolicitarOferta from './components/SolicitarOferta';
import { authService } from './services/api';
import FormularioInscripcion from './components/FormularioInscripcion';
// Dashboard con dos columnas
const Dashboard = () => {
  const [vistaActiva, setVistaActiva] = useState('crear');
  const user = authService.getCurrentUser();
  
  const handleLogout = () => {
    authService.logout();
    window.location.href = '/login';
  };

  return (
    <div style={styles.dashboard}>
      {/* Header */}
      <div style={styles.header}>
        <h1 style={styles.headerTitle}>Gestionytics - Panel de Control</h1>
        <div style={styles.userInfo}>
          <span style={styles.userName}>{user?.nombreUsuario}</span>
          <button onClick={handleLogout} style={styles.logoutButton}>
            Cerrar Sesión
          </button>
        </div>
      </div>

      {/* Contenedor de dos columnas */}
      <div style={styles.mainContainer}>
        {/* Columna Izquierda - Menú */}
        <div style={styles.sidebar}>
          <div style={styles.sidebarHeader}>
            <h3 style={styles.sidebarTitle}>Menú Principal</h3>
          </div>
          
          <button 
            onClick={() => setVistaActiva('crear')}
            style={{
              ...styles.menuButton,
              ...(vistaActiva === 'crear' ? styles.menuButtonActive : {})
            }}
          >
            ➕ Crear Oferta
          </button>
          
          <button 
            onClick={() => setVistaActiva('solicitar')}
            style={{
              ...styles.menuButton,
              ...(vistaActiva === 'solicitar' ? styles.menuButtonActive : {})
            }}
          >
            📝 Solicitar Oferta
          </button>

          <div style={styles.coordinadorInfo}>
            <p style={styles.coordinadorLabel}>Coordinador Asignado:</p>
            <p style={styles.coordinadorNombre}>{user?.coordinadorAsignado?.nombre}</p>
          </div>
        </div>

        {/* Columna Derecha - Contenido */}
        <div style={styles.content}>
          {vistaActiva === 'crear' ? <CrearOferta /> : <SolicitarOferta />}
        </div>
      </div>
    </div>
  );
};

const styles = {
  dashboard: {
    minHeight: '100vh',
    backgroundColor: '#f0f2f5',
    fontFamily: 'Arial, sans-serif'
  },
  header: {
    backgroundColor: '#2c3e50',
    color: 'white',
    padding: '15px 30px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    boxShadow: '0 2px 5px rgba(0,0,0,0.1)'
  },
  headerTitle: {
    margin: 0,
    fontSize: '24px'
  },
  userInfo: {
    display: 'flex',
    alignItems: 'center',
    gap: '20px'
  },
  userName: {
    fontSize: '16px',
    fontWeight: 'bold'
  },
  logoutButton: {
    backgroundColor: '#e74c3c',
    color: 'white',
    border: 'none',
    padding: '8px 16px',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: 'bold',
    transition: 'background-color 0.3s'
  },
  mainContainer: {
    display: 'flex',
    padding: '20px',
    gap: '20px',
    height: 'calc(100vh - 80px)'
  },
  sidebar: {
    width: '280px',
    backgroundColor: 'white',
    borderRadius: '8px',
    boxShadow: '0 2px 5px rgba(0,0,0,0.1)',
    padding: '20px',
    display: 'flex',
    flexDirection: 'column'
  },
  sidebarHeader: {
    borderBottom: '2px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '20px'
  },
  sidebarTitle: {
    margin: 0,
    color: '#2c3e50',
    fontSize: '18px'
  },
  menuButton: {
    width: '100%',
    padding: '15px',
    marginBottom: '10px',
    border: 'none',
    borderRadius: '6px',
    backgroundColor: '#f8f9fa',
    color: '#2c3e50',
    fontSize: '16px',
    fontWeight: 'bold',
    textAlign: 'left',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    transition: 'all 0.3s'
  },
  menuButtonActive: {
    backgroundColor: '#3498db',
    color: 'white',
    boxShadow: '0 2px 5px rgba(52,152,219,0.3)'
  },
  coordinadorInfo: {
    marginTop: 'auto',
    padding: '15px',
    backgroundColor: '#f8f9fa',
    borderRadius: '6px',
    border: '1px solid #e0e0e0'
  },
  coordinadorLabel: {
    margin: '0 0 5px 0',
    fontSize: '14px',
    color: '#7f8c8d'
  },
  coordinadorNombre: {
    margin: 0,
    fontSize: '16px',
    fontWeight: 'bold',
    color: '#2c3e50'
  },
  content: {
    flex: 1,
    backgroundColor: 'white',
    borderRadius: '8px',
    boxShadow: '0 2px 5px rgba(0,0,0,0.1)',
    padding: '25px',
    overflowY: 'auto'
  }
};

// Componente para rutas protegidas
const ProtectedRoute = ({ children }) => {
  if (!authService.isAuthenticated()) {
    return <Navigate to="/login" />;
  }
  return children;
};

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route 
          path="/dashboard" 
          element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          } 
        />
        <Route path="/" element={<Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
